
extension UIView {

    func attachViewController(viewController: UIViewController) -> Bool {
        guard let parentViewController = self.parentViewController
        else { return false }

        parentViewController.sbsdk_attach(viewController, in: self)
        return true
    }


    func detachViewController(viewController: UIViewController) {
        viewController.sbsdk_detach(viewController)
    }

    private var parentViewController: UIViewController? {
        return self.reactViewController()
    }

}
